// React component example
import React from 'react';

function App() {
    const [count, setCount] = useState(0);

    return (
        <div className="app">
            <h1>Counter: {count}</h1>
            <button onClick={() => setCount(c => c + 1)}>
                Increment
            </button>
        </div>
    );
}

export default App;
